package main
import ("bufio"; "fmt"; "os"; "strconv"; "strings")
func justify(words []string, maxWidth int) []string { res := []string{}; i := 0; for i < len(words) { j, total := i, 0; for j < len(words) && total+len(words[j])+(j-i) <= maxWidth { total += len(words[j]); j++ }; gaps := j - i - 1; var line string; if j == len(words) || gaps == 0 { line = strings.Join(words[i:j], " "); line += strings.Repeat(" ", maxWidth-len(line)) } else { spaces := maxWidth - total; base := spaces / gaps; extra := spaces % gaps; var b strings.Builder; for k := i; k < j-1; k++ { b.WriteString(words[k]); b.WriteString(strings.Repeat(" ", base+func() int { if k-i < extra { return 1 }; return 0 }())) }; b.WriteString(words[j-1]); line = b.String() }; res = append(res, line); i = j }; return res }
func main() { sc:=bufio.NewScanner(os.Stdin); lines:=[]string{}; for sc.Scan(){ lines=append(lines, sc.Text()) }; if len(lines)>0 { idx:=0; t,_:=strconv.Atoi(lines[idx]); idx++; out:=[]string{}; for tc:=0; tc<t; tc++ { n,_:=strconv.Atoi(lines[idx]); idx++; words:=append([]string{}, lines[idx:idx+n]...); idx += n; width,_:=strconv.Atoi(lines[idx]); idx++; ans:=justify(words,width); out=append(out, strconv.Itoa(len(ans))); for _,s := range ans { out=append(out, "|"+s+"|") }; if tc+1<t { out=append(out, "=") } }; fmt.Print(strings.Join(out, "\n")) } }
